FROM jsonb_to_recordset('[{"id": "cap-110-english-reading-passage-15", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(15-16)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "We’ve prepared many wonderful surprises for you at e-BeautiMed, BeautiMed’s\nonline store!\nSurprise 1      Join “BeautiMed Friend” online for free and get 2000\nBeautiMed points!\nSurprise 2      Already a “BeautiMed Friend” ? Come collect your free\ngift by entering your “BeautiMed Friend” card number at\ne-BeautiMed before 8/31.\nSurprise 3      Get 500 BeautiMed points by shopping at e-BeautiMed and\nyou’ll get 500 more points if you spend more than $1,000.\nSurprise 4      Shop at e-BeautiMed during 7/1-8/31 and you may win $5,000\nor free movie tickets!\nSurprise 5      Invite a friend to join “BeautiMed Friend” and you both can\nget 1000 points each!\n enter 輸入", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(15-16)", "child_qnums": [15, 16]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-17", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(17-18)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Joey: Lynn, have you tried Caldron? I’ve heard that restaurant is good.\nLynn: I have. I went there once for Tom’s party.\nJoey: And?\nLynn: Well, I never thought I would have to cook for myself when eating out.\nJoey: But it’s fun to cook your own food.\nLynn: I don’t see any fun in that. Besides, I want nice food.\nJoey: So you didn’t like the food there?\nLynn: Everything tasted the same. I mean, they were all cooked in the same boiling\npot. How could they taste different? I just kept throwing strange things into\nthe pot. I didn’t even know what half the things were made of.\nJoey: Don’t worry. Everything should be safe to eat after a hot bath in the pot.\nAnd you didn’t get sick after that, right? Besides, you tried something\ndifferent there. Still a good experience, I think?\nLynn: I don’t think we share the same idea of good experiences.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(17-18)", "child_qnums": [17, 18]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-19", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(19-21)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Below is a page from Katie’s diary.\nDear Diary,                                       June 7, 2011\nI was very sad to hear what happened to Woollie yesterday.\nWoollie was my favorite sheep. I have a storybook about Woollie.\nIt says when Woollie was four, he ran away from Mr. Armstrong’s\nfarm, and it took Mr. Armstrong six years to find Woollie. But\nWoollie had grown so much fleece that he didn’t even look like a\nsheep. Mr. Armstrong decided to cut his fleece on TV so everyone\ncould see. Daddy said this happened on the day I was born.\nWoollie’s fleece weighed 27 kg, and could make clothes for 20 large\nmen. I asked Daddy if his favorite vest was made from Woollie’s\nfleece. Daddy said no, because Woollie’s fleece was sold to collect\nmoney for sick kids. In the storybook, Woollie was taken to see\nMs. Stella Clark, the leader of our city then. They even had tea\ntogether. Daddy said Woollie did meet Ms. Clark, but he wasn’t\nsure if they had tea. Daddy said Woollie was put down because he\nwas too sick and there was no way to help him. I cried. I hope\nWoollie will be happy up there in the sky.\n fleece 羊毛 weigh 重達", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(19-21)", "child_qnums": [19, 20, 21]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-22", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(22-24)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Here’s The Piano Lesson, one of Henri\nMatisse’s most famous paintings. The boy in\nthe picture is the painter’s son, Pierre. In the\npicture, Pierre looks quite serious. Why? Well,\nlook at the yellow candle on the red piano. It’s\nalmost burned down. So maybe Pierre has\nalready practiced for hours. And Matisse uses a\nlot of gray, not a very fun color, right? It shows\nhow the poor kid feels, don’t you think?\nOn the top right corner, you can see a woman\nsitting straight on a seat. Is she Pierre’s piano\nteacher? Or his mother? Well, if you’re a\nMatisse fan, you’ll know this is in fact another\npainting by him, Woman on a High Stool. Interesting, right? Matisse likes to do that\na lot.  In fact, there’s another work by Matisse in the picture.  Did you find it?  Right!\nThe sculpture on the bottom left corner!\nMatisse painted this picture in 1916. Pierre was already 16 then, but the artist\npainted his son much younger than he really was. Pierre\nhad gone away to be a soldier, and Matisse didn’t know\nwhether he would come back. Maybe this is a worried\nfather’s way to remember the good old days.\n sculpture 雕像", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(22-24)", "child_qnums": [22, 23, 24]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-25", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(25-28)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "On Teachers’ Day, we thank our teachers for their hard work. We also celebrate\nthis day to remember Confucius, the great Chinese teacher from 2,500 years ago.\nWell, that’s everything we’re taught about Teachers’ Day. But, the first Teachers’\nDay was not on Confucius’s birthday, and it was not about thanking our teachers.\nIn 1930, Mr. Tai Shuang-qiu and other teachers celebrated the first Teachers’\nDay in Nanjing. But there was nothing to celebrate. Teachers were paid very little\nand not respected. These teachers took this chance to shout out their problems. They\nhad Teachers’ Day on June 6 because the date was easy to remember and near the\nend of the school year. This action by Mr. Tai and the other teachers was welcomed\nand followed by teachers from other cities. In 1939, the government made Teachers’\nDay a national holiday. However, it was on August 27, the day when Confucius’s\nbirthday was celebrated. Not everyone hailed this decision: Teachers’ Day was never\nabout Confucius, and Confucius couldn’t speak for all the teachers either.\nOne funny thing was that the government was wrong about the date of\nConfucius’s birthday. In 1952, people found out he was in fact born on September\n28. That was when we started to celebrate Teachers’ Day on Confucius’s real\nbirthday.\n respect 尊敬 government 政府", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(25-28)", "child_qnums": [25, 26, 27, 28]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-29", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(29-31)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Dear Traveler,\nYou have bought an NFR ticket online for a train that runs between White\nWater City and Cloud City.\nWe are sorry to tell you that, because of the typhoon last month, the Sand\nTown – Spring Town line will be closed between August 14 and 28 2016. During\nthis time, some trains will change lines and will not stop at a few stations.\nThere will be free buses to take travelers to these stations. Please check below\nfor the changes. Visit http://www.nfr.gov/ for more information.\nWe wish you a nice summer.\nLena Muller\nNational Formosa Railway\n1. Trains that run between Green City and Cloud\nCity will take the Smoke Town – Spring Town\nline, and will stop at every station. Below are\nthe trains that will change lines.                               White Water City\nTrain   New Line (from 8/14 to 8/28)\nGoing RL101 White Water City \u001f Cloud City\nSouth RL102 White Water City \u001f Spring Town                         Green City\nRL103 Green City \u001f Cloud City               Sand Town\nGoing RL201 Spring Town \u001f Green City                Gray Village        Smoke Town\nNorth RL202 Cloud City \u001f Green City\nBlack Town          Hill Town\n2. The free buses for the Sand Town – Spring\nTown line will wait at Green City (going south)                        Spring Town\nand Spring Town (going north) stations. No\nCloud City\nstop at Gray Village.\n line 路線", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(29-31)", "child_qnums": [29, 30, 31]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-32", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(32-34)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "SYRIA\nDarayya\nIn Darayya, a city in Syria, there’s a library, and it has 15,000 books on almost\nevery subject you can think of. However, it is different from any libraries you know:\nIt is a secret underground library, and only people in Darayya know where it is.\nOver the years, war has shaken Darayya badly. Every day, houses are bombed\nand people are killed. Stores are closed one after another, and so are schools. To\nhelp the kids in Darayya with their learning, Anas Ahmad, a 19-year-old student, and\nhis friends decided to build a library. They built the library under the ground to keep\nit safe from bombing. But it is dangerous to collect books for the library. Often,\nAhmad and his friends look for books in houses that were bombed. They need to be\ncareful because they may be killed in another bombing.\nYou may ask, “In a place like Darayya, would people be interested in books?”\n“Just like the body needs food, the mind needs books,” says one library user. In the\nlibrary, people enjoy their time of reading and forget about the terrible world above,\nso their life doesn’t seem so hard. Through reading, they are able to dream of a\nbetter life after war.\n war 戰爭 bomb 轟炸 seem 彷彿", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(32-34)", "child_qnums": [32, 33, 34]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-35", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(35-37)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "From:      Mia Loren <mloren@qmail.com>\nTo:        Dave Doddo <dd1225@qmail.com>\nDate:      Tue, Oct 24, 2017 at 10:01 AM\nSubject:   Daniel’s 5th Birthday Party – This Saturday!\nHello Dave,\nWe’re happy to invite you and your family to Daniel’s fifth birthday\nparty this Saturday.\nWe know we told you that the party would be in   35  . However,\nwe just moved to Carlton City last month, so the party won’t be in\nPattersons Town. It’ll be at Mosman Garden right next to Victor Zoo,\njust across from our new apartment. Please don’t go to Northbank\nPark next to our old house.\nThe weather report said that it may be rainy this weekend, but   36  .\nIf it rains, we’ll move the party inside our home. However, if we’re\n37   and it is fine, we’ll still have the party at the garden.\nAgain, we’re all very happy and excited to welcome you to join us for\nsome fun this weekend!\nBest,\nMia, Sam & Daniel", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(35-37)", "child_qnums": [35, 36, 37]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-english-reading-passage-38", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-110-english-reading", "question_type": "reading_passage", "question_text": "(38-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Usually I wouldn’t cross the park at this time\nof night. But walking around the park would take\nmore time, and it was raining so hard that I couldn’t\neven see clearly what was right before me. So I\nentered the park. And that was the first stupid thing\nI did tonight.\nSoon after I walked into the park, I saw a man under a tree up\nahead. My heart fell. The stories I’d heard about the park   38   into\nmy head at this moment. Anyone with a clear mind would just turn back.\nBut me? No. I did   39   stupid thing: I decided to hurry past him.\nJust when I was passing the man, he raised his head and gave me the\nstrangest smile ever. I got scared and started running. “Hey!” the man\nshouted from behind. “Wait!” He was running after me!\nI ran like crazy. I had hoped the trees would keep some rain off.\nAnd they   40  . But they also made the park look even darker. I\ncouldn’t see what was ahead of me. Then, I ran into something. It was\nthe man!\n“Don’t kill me!” I cried.\n“What? I   41   to give back your bag! You dropped it,” the man\ngave me my bag.\nNow, I felt saying that to the man was the stupidest thing I did\ntonight.\n ahead 在前面", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "cae155b30a50", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": null, "intro_line": "(38-41)", "child_qnums": [38, 39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
  id text, exam_id text, subject_id text, paper_id text,
